const { baseline_generation_capacity_mw, baseline_transmission_loss_rate_pct, aid_new_generation_capacity_mw, aid_transmission_loss_reduction_pct, baseline_diverse_generation_sources_count, aid_new_diverse_generation_sources_count, average_daily_peak_demand_mw } = inputs;

// Validate and sanitize inputs, ensuring non-negative values and handling potential non-numeric inputs
const bgc_mw = Math.max(0, parseFloat(baseline_generation_capacity_mw) || 0);
const btl_pct = Math.max(0, Math.min(100, parseFloat(baseline_transmission_loss_rate_pct) || 0)); // Cap at 100%
const angc_mw = Math.max(0, parseFloat(aid_new_generation_capacity_mw) || 0);
const atl_pct = Math.max(0, parseFloat(aid_transmission_loss_reduction_pct) || 0);
const bdgs_count = Math.max(0, parseInt(baseline_diverse_generation_sources_count) || 0);
const andgs_count = Math.max(0, parseInt(aid_new_diverse_generation_sources_count) || 0);
const adpd_mw = Math.max(0, parseFloat(average_daily_peak_demand_mw) || 0);

// 1. Calculate Post-Aid Total Generation Capacity
const post_aid_total_generation_capacity_mw = bgc_mw + angc_mw;

// 2. Calculate Post-Aid Transmission Loss Rate
// Loss reduction cannot make the rate negative, nor should it exceed 100% (unrealistic but for robustness).
const post_aid_transmission_loss_rate_pct = Math.max(0, Math.min(100, btl_pct - atl_pct));

// 3. Calculate Post-Aid Effective Supply Capacity
// Handles cases where total generation capacity might be zero.
const post_aid_effective_supply_capacity_mw = post_aid_total_generation_capacity_mw * (1 - (post_aid_transmission_loss_rate_pct / 100));

// 4. Calculate Energy Mix Diversification Index
const post_aid_diverse_sources_count = bdgs_count + andgs_count;
let post_aid_energy_diversification_index;
if (post_aid_diverse_sources_count <= 1) {
    post_aid_energy_diversification_index = 0; // No diversification if 1 or less source
} else {
    // Normalizing against an 'ideal' number of sources, e.g., 5. This provides a score from 0 to 1.
    const ideal_diverse_sources = 5;
    post_aid_energy_diversification_index = Math.min(1, post_aid_diverse_sources_count / ideal_diverse_sources);
}

// 5. Calculate Capacity Adequacy Score
// How well effective supply meets demand. Handles zero demand scenarios gracefully.
let capacity_adequacy_score = 0;
if (adpd_mw > 0) {
    capacity_adequacy_score = Math.min(1, post_aid_effective_supply_capacity_mw / adpd_mw);
} else {
    // If no demand, capacity is considered fully adequate from a resilience perspective.
    capacity_adequacy_score = 1;
}

// 6. Combine factors for Overall Grid Resilience Score (weighted average)
// Capacity adequacy is weighted higher for immediate operational resilience.
// Diversification is crucial for long-term strategic resilience against shocks.
const capacity_weight = 0.6;
const diversification_weight = 0.4;
let grid_resilience_score = (capacity_adequacy_score * capacity_weight + post_aid_energy_diversification_index * diversification_weight) * 100;

// Ensure the final score is within the 0-100 range.
grid_resilience_score = Math.max(0, Math.min(100, grid_resilience_score));

return {
    post_aid_total_generation_capacity_mw: parseFloat(post_aid_total_generation_capacity_mw.toFixed(2)),
    post_aid_effective_supply_capacity_mw: parseFloat(post_aid_effective_supply_capacity_mw.toFixed(2)),
    post_aid_transmission_loss_rate_pct: parseFloat(post_aid_transmission_loss_rate_pct.toFixed(2)),
    post_aid_energy_diversification_index: parseFloat(post_aid_energy_diversification_index.toFixed(2)),
    grid_resilience_score: parseFloat(grid_resilience_score.toFixed(2))
};
